  KEY `idx_coc_template_no` (`coc_template_no`),
  KEY `idx_model_no` (`model_no`)
) ENGINE=InnoDB AUTO_INCREMENT=40 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='COC模板主表';
