--
-- Table structure for table `xml_version`
--

DROP TABLE IF EXISTS `xml_version`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `xml_version` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `file_id` bigint NOT NULL COMMENT '文件ID',
  `version` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '版本号',
  `file_path` varchar(500) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '文件路径',
  `change_type` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '变更类型',
  `change_desc` text COLLATE utf8mb4_unicode_ci COMMENT '变更描述',
  `diff_content` longtext COLLATE utf8mb4_unicode_ci COMMENT '差异内容',
  `create_by` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '创建者',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  PRIMARY KEY (`id`),
  KEY `idx_file_id` (`file_id`)
) ENGINE=InnoDB AUTO_INCREMENT=24 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='XML版本历史表';
